  ('social-worker-moex-01824', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一位居住在家的慢性精神疾病案主，白天在某一衛生局立案的精神服務機構接受服務，內容包括職前訓 練、庇護工作訓練、個別及團體治療、職能治療等項目，以期達到社會復歸的目的，請問這是屬於下列 那一項服務？', '["居家治療", "社區復健中心", "康復之家", "精神障礙會所（clubhouse）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01825', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '臺灣於2014年通過《身心障礙者權利公約施行法》，請問下列那一項不符合聯合國《身心障礙者權利公 約》（CRPD）的一般性意見與指導原則？', '["“通用設計”不應排除於必要情況下，為特定身心障礙者群體提供輔助用具", "尊重差異，接受身心障礙者是人之多元性之一部分與人類之一份子", "於所有關於身心障礙兒童之行動中，應以整體家庭最佳利益為首要考量", "為了協助確保身心障礙者有效獲得司法保護，締約國應促進對司法領域工作人員，包括警察與監所人 員進行適當之培訓"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01826', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '提供給遊民緊急、短期、中長期服務，不僅改善遊民的生活，也有助於社會融合。請問上述的陳述最符 合以下那一個倫理學的觀點？', '["效用主義（utilitarianism）", "康德主義的義務論（Kantianism）", "直覺論的倫理觀（intuitionist）", "相對論（relativism）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01827', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下對於社會工作倫理與原則的陳述，何者最適當？', '["顧及個案隱私是最重要的，無論任何情況下都必須絕對保密，完全不能對外透露", "社會工作者把早年的經驗投射在個案身上，稱之為情感轉移", "社會工作者需要有自我照顧的能力", "社會工作者在評估時不可將自身的經驗直覺做為評估的資訊來源之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01828', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關臺灣社會工作師倫理守則之敘述，下列何者正確？', '["根據社會工作師法，社會工作倫理守則由臺灣社會工作專業人員協會訂定", "當個案透過監護人或法律代表放棄其隱私權，社會工作者得公開個案資訊", "當面臨倫理衝突時，社會工作者應以個案自我決定為最優先考量原則", "個案死亡之後，其隱私權之需求即消滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01829', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當社會工作人員認為案主的文化、階層、膚色都是沒有差別的，而且傳統慣用的工作方法也適用於所有 人身上，請問這是於Cross等人（1989）所提出的文化能力光譜的那一個階段？', '["文化盲點（cultural blindness）", "文化無能（cultural incapacity）", "文化初始能力（cultural pre-competence）", "文化基本能力（basic cultural competence）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01830', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下對於社會工作理論的敘述，何者正確？', '["任務中心模型（task-centered model）的個案工作不適用於非自願性案主", "優勢觀點強調社會工作者乃是助人關係中的指導者", "結構的社會工作（structural social work）主張排除社會因素，以理解個人為中心", "危機介入理論認為當壓力事件發生時，若立即介入，所有的危機多數在6到8個星期內會獲得解決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
